1# 获取系统和用户的PATH
$machinePath = [Environment]::GetEnvironmentVariable("Path", "Machine") -split ';'
$userPath = [Environment]::GetEnvironmentVariable("Path", "User") -split ';'

# 创建一个查找表来存储路径来源
$pathSource = @{}
$machinePath | ForEach-Object { if ($_) { $pathSource[$_.ToLower()] = "Machine" } }
$userPath | ForEach-Object { if ($_) { $pathSource[$_.ToLower()] = "User" } }

# 搜索并显示结果
$env:Path -split ';' | 
    Where-Object { $_ -like "*powershell*" } | 
    ForEach-Object { 
        [PSCustomObject]@{
            '路径' = $_
            '来源' = $pathSource[$_.ToLower()]
        }
    } | Format-Table -AutoSize -Wrap
